#include <bits/stdc++.h>
using namespace std;
int C[30][30];
int main(){
    for(int i=0;i<=26;i++)
        for(int j=0;j<=i;j++)
            C[i][j]=(j==0 || j==i?1:C[i-1][j]+C[i-1][j-1]);
    string s;
    cin>>s;
    if(s.size()>6){
        printf("0");
        return 0;
    }
    for(int i=0;i<s.size();i++){
        if(s[i]<'a' || s[i]>'z' || (i>0 && s[i-1]>=s[i])){
            printf("0");
            return 0;
        }
    }
    int n=s.size(),ans=0;
    for(int i=1;i<n;i++)
        ans+=C[26][i];
    s=" "+s;
    for(int i=1;i<=n;i++){
    	for(int j=(i==1?0:s[i-1]-'a'+1);j<s[i]-'a';j++)
    	    ans+=C[26-j-1][n-i];
    }
    printf("%d",++ans);
    return 0;
}
